window.PACTO.acts["reg-2021-1148"]={"label": "REGOLAMENTO (UE) 2021/1148 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 2021/1148", "file": "ext-reg-2021-1148.html", "external": true, "version": "consolidato 2026-06-12", "eurlex": "https://eur-lex.europa.eu/eli/reg/2021/1148/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[null, "<p class=\"norm\">Il presente regolamento istituisce lo Strumento di sostegno finanziario per la gestione delle frontiere e la politica dei visti («Strumento») nell’ambito del Fondo per la gestione integrata delle frontiere («Fondo») per il periodo compreso tra il 1<span class=\"superscript\">o</span> gennaio 2021 e il 31 dicembre 2027.</p>"], [null, "<p class=\"norm\">Il presente regolamento istituisce il Fondo unitamente al regolamento (UE) 2021/1077 per il periodo compreso tra il 1<span class=\"superscript\">o</span> gennaio 2021 e il 31 dicembre 2027.</p>"], [null, "<p class=\"norm\">Il presente regolamento stabilisce l’obiettivo strategico dello Strumento, gli obiettivi specifici dello Strumento e le misure intese ad attuare tali obiettivi specifici, il bilancio per il periodo tra il 1<span class=\"superscript\">o</span> gennaio 2021 e il 31 dicembre 2027, le forme di finanziamento dell’Unione e le regole di erogazione del finanziamento.</p>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"norm\">Ai fini del presente regolamento si applicano le seguenti definizioni:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«valico di frontiera»: ogni valico di frontiera quale definito all’articolo 2, punto 8), del regolamento (UE) 2016/399;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«gestione europea integrata delle frontiere»: la gestione europea integrata delle frontiere di cui all’articolo 3 del regolamento (UE) 2019/1896;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«frontiere esterne»: le frontiere esterne quali definite all’articolo 2, punto 2), del regolamento (UE) 2016/399 e le frontiere interne a cui i controlli non sono ancora stati soppressi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>4) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«sezione di frontiera esterna»: la sezione di frontiera esterna quale definita all’articolo 2, punto 11), del regolamento (UE) 2019/1896;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>5) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«punto di crisi» (<span class=\"italics\">hotspot</span>): un punto di crisi quale definito all’articolo 2, punto 23), del regolamento (UE) 2019/1896;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>6) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«frontiere interne a cui i controlli non sono ancora stati soppressi»:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il confine comune fra uno Stato membro che attua integralmente l’acquis di Schengen e uno Stato membro che è tenuto ad applicarlo integralmente in conformità del suo atto di adesione ma per il quale non è ancora entrata in vigore la relativa decisione del Consiglio che lo autorizza ad applicare tale acquis in misura integrale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il confine comune fra due Stati membri tenuti ad applicare integralmente l’acquis di Schengen in conformità dei rispettivi atti di adesione, ma per i quali non è ancora entrata in vigore la relativa decisione del Consiglio che li autorizza ad applicare tale acquis in misura integrale;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>7) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«situazione di emergenza»: una situazione derivante da un’urgente ed eccezionale pressione, in cui si è verificato, si verifica o si prevede che si verifichi un afflusso massiccio o sproporzionato di cittadini di paesi terzi attraverso le frontiere esterne di uno o più Stati membri o in cui episodi connessi all’immigrazione illegale o alla criminalità transfrontaliera si verificano alle frontiere esterne di uno o più Stati membri e hanno un impatto decisivo sulla sicurezza delle frontiere al punto di rischiare di compromettere il funzionamento dello spazio Schengen, o qualsiasi altra situazione per la quale sia stato debitamente dimostrato che è necessaria un’azione immediata alle frontiere esterne nell’ambito degli obiettivi dello Strumento;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>8) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«azioni specifiche»: progetti transnazionali o nazionali che apportano un valore aggiunto dell’Unione in conformità degli obiettivi dello Strumento, per i quali uno, più o tutti gli Stati membri possono ricevere una dotazione aggiuntiva per i rispettivi programmi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>9) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«sostegno operativo»: la parte della dotazione di uno Stato membro che può essere usata per finanziare il sostegno alle autorità pubbliche responsabili dello svolgimento dei compiti e della fornitura dei servizi che costituiscono un servizio pubblico per l’Unione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>10) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«azioni dell’Unione»: progetti transnazionali o progetti di particolare interesse per l’Unione attuati in conformità degli obiettivi dello Strumento;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>11) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«azione di solidarietà»: un’azione il cui ambito di applicazione è definito all’articolo 56, paragrafo 2, lettera b), del regolamento (UE) 2024/1351 del Parlamento europeo del Consiglio (\n<span class=\"superscript\">1</span>\n), finanziata dai contributi finanziari forniti dagli Stati membri di cui all’articolo 64, paragrafo 1, di tale regolamento.</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "3": {"label": "Articolo 3", "heading": "Obiettivi dello Strumento", "anchor": "art_3", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Nell’ambito del Fondo, l’obiettivo strategico dello Strumento è garantire una solida ed efficace gestione europea integrata delle frontiere alle frontiere esterne, contribuendo in tal modo a garantire un livello elevato di sicurezza interna nell’Unione tutelando al tempo stesso la libera circolazione delle persone al suo interno, nel pieno rispetto del pertinente acquis dell’Unione e degli obblighi internazionali dell’Unione e degli Stati membri derivanti dagli strumenti internazionali di cui sono parti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nell’ambito dell’obiettivo strategico di cui al paragrafo 1, lo Strumento contribuisce ai seguenti obiettivi specifici:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere un’efficace gestione europea integrata delle frontiere alle frontiere esterne, attuata dalla guardia di frontiera e costiera europea nell’ambito della responsabilità condivisa dell’Agenzia europea della guardia di frontiera e costiera e delle autorità nazionali preposte alla gestione delle frontiere, per agevolare gli attraversamenti legittimi delle frontiere, prevenire e individuare l’immigrazione illegale e la criminalità transfrontaliera e gestire in modo efficace i flussi migratori:</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere la politica comune in materia di visti per garantire un approccio armonizzato nel rilascio dei visti e facilitare i viaggi legittimi, contribuendo nel contempo a prevenire il rischio migratorio in termini di migrazione e sicurezza.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nell’ambito degli obiettivi specifici di cui al paragrafo 2, lo Strumento è attuato mediante le misure di attuazione elencate all’allegato II.</div>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Non discriminazione e rispetto dei diritti fondamentali", "anchor": "art_4", "frags": [[null, "<p class=\"norm\">Le azioni finanziate nell’ambito dello Strumento sono attuate nel pieno rispetto dei diritti e dei principi sanciti dall’acquis dell’Unione e dalla Carta nonché degli obblighi internazionali dell’Unione in materia di diritti fondamentali, garantendo in particolare l’osservanza dei principi di non discriminazione e di non respingimento.</p>"]]}, "5": {"label": "Articolo 5", "heading": "Ambito di applicazione del sostegno", "anchor": "art_5", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Nell’ambito dei suoi obiettivi e in conformità delle misure di attuazione elencate all’allegato II, lo Strumento sostiene in particolare le azioni elencate nell’allegato III.</div>\n</div>"], [null, "<p class=\"norm\">Per far fronte a circostanze impreviste o nuove, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 31 per modificare l’elenco delle azioni di cui all’allegato III, al fine di aggiungere nuove azioni.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per conseguire i suoi obiettivi, lo Strumento può sostenere, in linea con le priorità dell’Unione, azioni di cui all’allegato III nei paesi terzi e in relazione a tali paesi, se del caso, in conformità dell’articolo 20.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per quanto riguarda le azioni nei paesi terzi e in relazione a tali paesi, la Commissione e gli Stati membri, insieme al servizio europeo per l’azione esterna, assicurano, conformemente alle rispettive competenze, il coordinamento con le politiche, le strategie e gli strumenti pertinenti dell’Unione. Provvedono in particolare affinché le azioni nei paesi terzi e in relazione a tali paesi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">siano svolte in sinergia e coerenza con altre azioni esterne dell’Unione sostenute da altri strumenti dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">siano coerenti con la politica esterna dell’Unione, rispettino il principio della coerenza delle politiche per lo sviluppo e siano coerenti con i documenti di programmazione strategica per la regione o il paese in questione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">siano incentrate su misure non orientate allo sviluppo; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">servano gli interessi delle politiche interne dell’Unione e siano coerenti con le attività intraprese all’interno dell’Unione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le seguenti azioni non sono ammissibili:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le azioni di cui al punto 1, lettera a), dell’allegato III alle frontiere interne a cui i controlli non sono ancora stati soppressi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le azioni relative al ripristino temporaneo del controllo di frontiera alle frontiere interne ai sensi dell’articolo 2, punto 1), del regolamento (UE) 2016/399;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le azioni la cui finalità principale è il controllo doganale.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">In deroga al primo comma del presente paragrafo, nelle situazioni di emergenza le azioni ivi indicate possono essere considerate ammissibili.</p>"]]}, "6": {"label": "Articolo 6", "heading": "Principi generali", "anchor": "art_6", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il sostegno fornito nel quadro dello Strumento integra l’intervento nazionale, regionale e locale e mira ad apportare valore aggiunto dell’Unione al conseguimento degli obiettivi dello Strumento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione e gli Stati membri garantiscono che il sostegno fornito nel quadro dello Strumento e dagli Stati membri sia coerente con le pertinenti azioni, politiche e priorità dell’Unione e sia complementare al sostegno fornito nel quadro di altri strumenti dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Strumento è attuato in regime di gestione diretta, concorrente o indiretta in conformità dell’articolo 62, paragrafo 1, primo comma, lettere a), b) e c), del regolamento finanziario.</div>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Dotazione di bilancio", "anchor": "art_7", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La dotazione finanziaria per l’attuazione dello Strumento per il periodo compreso tra il 1<span class=\"superscript\">o</span> gennaio 2021 e il 31 dicembre 2027 è fissata a 5 241 000 000  EUR a prezzi correnti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In conseguenza dell’adeguamento specifico dei programmi previsto dall’articolo 5 del regolamento (UE, Euratom) 2020/2093, l’importo di cui al paragrafo 1 del presente articolo è maggiorato di una dotazione aggiuntiva pari a 1 000 000 000  EUR a prezzi costanti 2018, come specificato all’allegato II di detto regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La dotazione finanziaria è così utilizzata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">3 668 000 000  EUR sono stanziati per i programmi degli Stati membri, di cui 200 568 000  EUR sono stanziati per il regime di transito speciale di cui all’articolo 17;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">1 573 000 000  EUR sono stanziati per lo strumento tematico di cui all’articolo 8.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La dotazione aggiuntiva di cui al paragrafo 2 è assegnata allo strumento tematico di cui all’articolo 8.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Su iniziativa della Commissione, fino allo 0,52 % della dotazione finanziaria è destinato all’assistenza tecnica di cui all’articolo 35 del regolamento (UE) 2021/1060 per l’attuazione dello Strumento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Conformemente alle pertinenti disposizioni dei rispettivi accordi di associazione, sono adottate intese per specificare la natura e le modalità della partecipazione allo Strumento da parte dei paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen. Non appena possibile dopo la notifica, da parte del paese interessato, della decisione di accettare il contenuto dello Strumento e di dare attuazione ad esso nel proprio ordinamento giuridico interno, a norma del pertinente accordo di associazione, la Commissione presenta una raccomandazione al Consiglio per l’avvio di negoziati su tali accordi a norma dell’articolo 218, paragrafo 3, TFUE. Non appena ricevuta la raccomandazione, il Consiglio delibera senza ritardo per decidere di autorizzare l’avvio di tali negoziati. I contributi finanziari provenienti da tali paesi si aggiungono alle risorse complessive disponibili a titolo della dotazione finanziaria di cui al paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">A norma dell’articolo 26 del regolamento (UE) 2021/1060, fino al 5 % della dotazione iniziale a uno Stato membro, proveniente da uno qualsiasi dei fondi nell’ambito di tale regolamento in regime di gestione concorrente, può essere trasferito allo Strumento in regime di gestione diretta o indiretta su richiesta di tale Stato membro. La Commissione dà esecuzione a tali risorse direttamente, in conformità dell’articolo 62, paragrafo 1, primo comma, lettera a), del regolamento finanziario, o indirettamente, in conformità della lettera c) del medesimo comma. Tali risorse sono utilizzate a beneficio dello Stato membro interessato.</div>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Disposizioni generali di attuazione dello strumento tematico", "anchor": "art_8", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’importo di cui all’articolo 7, paragrafo 3, lettera b), è stanziato in maniera flessibile mediante uno strumento tematico in regime di gestione concorrente, diretta o indiretta, secondo quanto stabilito nei programmi di lavoro. Data la natura interna dello Strumento, lo strumento tematico serve principalmente la politica interna dell’Unione in linea con gli obiettivi specifici indicati all’articolo 3, paragrafo 2.</div>\n</div>"], [null, "<p class=\"norm inline-element\">I finanziamenti dello strumento tematico sono usati per le sue componenti, che sono:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le azioni specifiche;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le azioni dell’Unione; e</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’assistenza emergenziale di cui all’articolo 25.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">L’assistenza tecnica su iniziativa della Commissione di cui all’articolo 35 del regolamento (UE) 2021/1060 riceve sostegno anche dall’importo di cui all’articolo 7, paragrafo 3, lettera b), del presente regolamento.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I finanziamenti dello strumento tematico sono usati per affrontare priorità con un elevato valore aggiunto dell’Unione o per rispondere a necessità urgenti, in linea con le priorità concordate dell’Unione di cui all’allegato II, compresa la necessità di proteggere le frontiere esterne e di prevenire e individuare la criminalità transfrontaliera alle frontiere esterne, in particolare il traffico di migranti e la tratta di esseri umani e l’immigrazione irregolare, nonché di gestire efficacemente i flussi migratori e sostenere la politica comune in materia di visti.</div>\n</div>"], [null, "<p class=\"norm\">I finanziamenti di cui al presente paragrafo, primo comma, ad eccezione di quelli utilizzati per l’assistenza emergenziale a norma dell’articolo 25, sostengono unicamente le azioni elencate all’allegato III.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione avvia un dialogo con le organizzazioni della società civile e le reti pertinenti, in particolare al fine di preparare e valutare i programmi di lavoro per le azioni dell’Unione finanziate nell’ambito dello Strumento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Quando i finanziamenti dello strumento tematico sono erogati agli Stati membri in regime di gestione diretta o indiretta, la Commissione garantisce che non siano selezionati progetti oggetto di un parere motivato emesso dalla Commissione a norma dell’articolo 258 TFUE relativo a procedure di infrazione che mettano in dubbio la legittimità e la regolarità delle spese o l’esecuzione dei progetti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Ai fini dell’articolo 23 e dell’articolo 24, paragrafo 2, del regolamento (UE) 2021/1060, quando i finanziamenti dello strumento tematico sono attuati in regime di gestione concorrente, gli Stati membri interessati garantiscono e la Commissione si assicura che le azioni previste non siano oggetto di un parere motivato emesso dalla Commissione relativo a procedure di infrazione a norma dell’articolo 258 TFUE che mettano in dubbio la legittimità e la regolarità delle spese o l’esecuzione delle azioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La Commissione stabilisce l’importo totale da mettere a disposizione dello strumento tematico nell’ambito degli stanziamenti annuali del bilancio dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">La Commissione adotta, mediante atti di esecuzione, decisioni di finanziamento di cui all’articolo 110 del regolamento finanziario riguardanti lo strumento tematico che identificano gli obiettivi e le azioni da sostenere e specificano gli importi di ciascuna componente di cui al paragrafo 1, secondo comma, del presente articolo. Le decisioni di finanziamento possono essere annuali o pluriennali e possono riguardare una o più componenti dello strumento tematico di cui al paragrafo 1, secondo comma, del presente articolo. Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 32, paragrafo 3, del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">La Commissione garantisce che la distribuzione delle risorse tra gli obiettivi specifici indicati all’articolo 3, paragrafo 2, sia equa e trasparente. La Commissione riferisce in merito all’utilizzo e alla distribuzione dello strumento tematico tra le componenti di cui al paragrafo 1, secondo comma, del presente articolo, compreso il sostegno fornito ad azioni nei paesi terzi o in relazione a tali paesi nell’ambito delle azioni dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">A seguito dell’adozione della decisione di finanziamento di cui al paragrafo 7, la Commissione può modificare di conseguenza i programmi degli Stati membri.</div>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Ambito di applicazione", "anchor": "art_9", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La presente sezione si applica all’importo di cui all’articolo 7, paragrafo 3, lettera a), e alle risorse aggiuntive da attuare in regime di gestione concorrente conformemente alla decisione di finanziamento riguardante lo strumento tematico di cui all’articolo 8.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il sostegno nell’ambito della presente sezione è attuato in regime di gestione concorrente in conformità dell’articolo 63 del regolamento finanziario e del regolamento (UE) 2021/1060.</div>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Risorse di bilancio", "anchor": "art_10", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’importo di cui all’articolo 7, paragrafo 3, lettera a), è stanziato per i programmi degli Stati membri indicativamente come segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">3 057 000 000  EUR conformemente all’allegato I;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">611 000 000  EUR per l’adeguamento delle dotazioni ai programmi degli Stati membri di cui all’articolo 14, paragrafo 1.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora l’importo di cui al paragrafo 1, lettera b), del presente articolo non sia stanziato per intero, l’importo residuo può essere aggiunto all’importo di cui all’articolo 7, paragrafo 3, lettera b).</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il sostegno fornito nell’ambito del presente regolamento può essere finanziato, ai fini di azioni di solidarietà, mediante contributi degli Stati membri e di altri donatori pubblici o privati come entrate con destinazione specifica esterne a norma dell’articolo 21, paragrafo 5, del regolamento finanziario.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "11": {"label": "Articolo 11", "heading": "Prefinanziamento", "anchor": "art_11", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Conformemente all’articolo 90, paragrafo 4, del regolamento (UE) 2021/1060, il prefinanziamento per lo Strumento è versato in frazioni annuali prima del 1<span class=\"superscript\">o</span> luglio di ogni anno, subordinatamente alla disponibilità di finanziamenti, come segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2021: 4 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2022: 3 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2023: 5 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2024: 5 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2025: 5 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2026: 5 %.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se un programma di uno Stato membro è adottato dopo il 1<span class=\"superscript\">o</span> luglio 2021, le frazioni precedenti sono versate nell’anno di adozione.</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Tassi di cofinanziamento", "anchor": "art_12", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il contributo a carico del bilancio dell’Unione non supera il 75 % del totale delle spese ammissibili per un progetto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il contributo a carico del bilancio dell’Unione può essere aumentato fino al 90 % del totale delle spese ammissibili per i progetti attuati nell’ambito di azioni specifiche.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il contributo a carico del bilancio dell’Unione può essere aumentato fino al 90 % del totale delle spese ammissibili per le azioni elencate all’allegato IV.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il contributo a carico del bilancio dell’Unione può essere aumentato fino al 100 % del totale delle spese ammissibili per il sostegno operativo, compreso il regime di transito speciale di cui all’articolo 17.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il contributo a carico del bilancio dell’Unione può essere aumentato fino al 100 % del totale delle spese ammissibili in conformità dell’articolo 85, paragrafo 2 o 3, del regolamento (UE) 2018/1240.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il contributo a carico del bilancio dell’Unione può essere aumentato fino al 100 % del totale delle spese ammissibili per l’assistenza emergenziale di cui all’articolo 25.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il contributo a carico del bilancio dell’Unione può essere aumentato fino al 100 % del totale delle spese ammissibili per l’assistenza tecnica su iniziativa degli Stati membri, entro i limiti di cui all’articolo 36, paragrafo 5, lettera b), punto vi), del regolamento (UE) 2021/1060.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7 bis.  </span>\n<div class=\"norm inline-element\">Il contributo a carico del bilancio dell’Unione può essere aumentato fino al 100 % del totale delle spese ammissibili per le azioni di solidarietà.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">La decisione della Commissione che approva il programma di uno Stato membro fissa il tasso di cofinanziamento e l’importo massimo del sostegno dello Strumento per le tipologie di azione coperte dal contributo di cui ai paragrafi da 1 a 7.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La decisione della Commissione che approva il programma di uno Stato membro indica per ciascuna tipologia di azione se il tasso di cofinanziamento è applicato in relazione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al contributo totale, che comprende il contributo pubblico e il contributo privato; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">solo al contributo pubblico.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Programmi degli Stati membri", "anchor": "art_13", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro garantisce che le priorità affrontate nei propri programmi siano coerenti con le priorità e le sfide dell’Unione nei settori della gestione delle frontiere e della politica dei visti, rispondano a tali sfide e priorità e siano pienamente in linea con il pertinente acquis dell’Unione e con gli obblighi internazionali dell’Unione e degli Stati membri derivanti dagli strumenti internazionali di cui sono parti. Nel definire le priorità dei loro programmi gli Stati membri garantiscono che questi tengano conto in modo adeguato delle misure di attuazione elencate all’allegato II.</div>\n</div>"], [null, "<p class=\"norm\">Data la natura interna dello Strumento, i programmi degli Stati membri servono principalmente la politica interna dell’Unione in conformità degli obiettivi specifici indicati all’articolo 3, paragrafo 2, del presente regolamento.</p>"], [null, "<p class=\"norm\">La Commissione valuta i programmi degli Stati membri in conformità dell’articolo 23 del regolamento (UE) 2021/1060.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nell’ambito delle risorse stanziate all’articolo 10, paragrafo 1, e fatto salvo il paragrafo 3 del presente articolo, ogni Stato membro assegna nel proprio programma almeno il 10 % delle risorse stanziate ai sensi dell’articolo 10, paragrafo 1, all’obiettivo specifico indicato all’articolo 3, paragrafo 2, lettera b).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono stanziare meno della percentuale minima di cui al paragrafo 2 unicamente qualora motivino in maniera dettagliata la scelta nel loro programma spiegando i motivi per cui l’assegnazione di risorse inferiori a tale soglia non pregiudichi il conseguimento dell’obiettivo pertinente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione garantisce che le conoscenze e le competenze delle pertinenti agenzie decentrate, in particolare l’Agenzia europea della guardia di frontiera e costiera, eu-LISA e l’Agenzia dell’Unione europea per i diritti fondamentali, istituita dal regolamento (CE) n. 168/2007 del Consiglio (\n<span class=\"superscript\">2</span>\n), siano prese in considerazione per le materie di loro competenza, in una fase iniziale e in modo tempestivo, nello sviluppo dei programmi degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione consulta l’Agenzia europea della guardia di frontiera e costiera sulle azioni rientranti nel sostegno operativo al fine di garantire la coerenza e la complementarità tra le azioni dell’Agenzia europea della guardia di frontiera e costiera e quelle degli Stati membri per quanto riguarda la gestione delle frontiere, al fine di evitare il doppio finanziamento e garantire efficienza sotto il profilo dei costi. Ove necessario, la Commissione consulta eu-LISA in merito alle azioni incluse nel sostegno operativo per le quali eu-LISA dispone di competenze specifiche conformemente al suo mandato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Se del caso, la Commissione può coinvolgere le agenzie decentrate competenti, compresi quelli di cui al paragrafo 4, nei compiti di sorveglianza e valutazione specificati alla sezione 5, in particolare per garantire che le azioni attuate con il sostegno dello Strumento siano conformi al pertinente acquis dell’Unione e alle priorità concordate dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">A seguito dell’adozione di raccomandazioni nel quadro del presente regolamento conformemente al regolamento (UE) n. 1053/2013 e della formulazione di raccomandazioni nel quadro dello svolgimento di valutazioni delle vulnerabilità a norma del regolamento (UE) 2019/1896, lo Stato membro interessato esamina, di concerto con la Commissione, l’approccio più adeguato per attuare queste raccomandazioni con il sostegno dello Strumento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">La Commissione, se del caso, coinvolge l’Agenzia europea della guardia di frontiera e costiera nel processo d’esame dell’approccio più adeguato per attuare le raccomandazioni di cui al paragrafo 7 con il sostegno dello Strumento. In tale contesto, la Commissione, se del caso, può avvalersi delle competenze di altre agenzie dell’Unione in merito a questioni specifiche che rientrano nella loro sfera di competenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Nell’attuare il paragrafo 7 lo Stato membro interessato rende prioritaria per il suo programma l’attuazione di misure volte a rimediare alle carenze riscontrate, in particolare quelle volte a rimediare a carenze gravi e a valutazioni di non conformità.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Se necessario, il programma dello Stato membro in questione è modificato in conformità dell’articolo 24 del regolamento (UE) 2021/1060 per tenere conto delle raccomandazioni di cui al paragrafo 7 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">In cooperazione e in consultazione con la Commissione e con l’Agenzia europea della guardia di frontiera e costiera in funziona dei suoi settori di competenza, lo Stato membro interessato può riassegnare risorse stanziate nell’ambito del suo programma, comprese quelle programmate per il sostegno operativo, per conformarsi alle raccomandazioni di cui al paragrafo 7 nel caso in cui tali raccomandazioni abbiano implicazioni finanziarie.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">12.  </span>\n<div class=\"norm inline-element\">Lo Stato membro che decida di attuare un progetto sostenuto dallo Strumento con un paese terzo o in un paese terzo consulta la Commissione prima dell’approvazione del progetto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">13.  </span>\n<div class=\"norm inline-element\">Lo Stato membro che decida di attuare un’azione con un paese terzo, in un paese terzo o in relazione a un paese terzo, con il sostegno dello Strumento, in materia di sorveglianza, individuazione, identificazione, localizzazione, prevenzione e intercettazione degli attraversamenti non autorizzati delle frontiere al fine di individuare, prevenire e combattere l’immigrazione irregolare e la criminalità transfrontaliera o di contribuire alla protezione e a salvare la vita dei migranti garantisce di aver notificato alla Commissione ogni accordo di cooperazione bilaterale o multilaterale con tale paese terzo conformemente all’articolo 76, paragrafo 3, del regolamento (UE) 2019/1896.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">14.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per quanto riguarda le attrezzature, compresi i mezzi di trasporto e i sistemi TIC necessari per un controllo di frontiera efficace e sicuro, incluse le operazioni di ricerca e soccorso, e acquistati con il sostegno dello Strumento:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al momento di avviare le procedure di acquisto delle attrezzature e dei sistemi TIC che dovranno essere sviluppati con il sostegno dello Strumento, gli Stati membri assicurano che siano rispettate le norme stabilite in conformità degli articoli 16 e 64 del regolamento (UE) 2019/1896;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tutte le attrezzature operative su larga scala per la gestione delle frontiere, come i mezzi di trasporto e di sorveglianza aerei e marittimi, acquistate dagli Stati membri sono registrate nel parco attrezzature tecniche dell’Agenzia europea della guardia di frontiera e costiera al fine di rendere tali attrezzature disponibili conformemente all’articolo 64, paragrafo 9, del regolamento (UE) 2019/1896;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">possono inoltre essere utilizzati nei seguenti settori complementari: controllo doganale, operazioni marittime di carattere multifunzionale e ai fini del conseguimento degli obiettivi del Fondo Sicurezza interna e del Fondo Asilo, migrazione e integrazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">onde sostenere una pianificazione coerente di sviluppo delle capacità per la guardia di frontiera e costiera europea e il possibile ricorso ad appalti congiunti, gli Stati membri comunicano alla Commissione, nell’ambito della rendicontazione richiesta a norma dell’articolo 29, la pianificazione pluriennale disponibile per le attrezzature di cui è previsto l’acquisto nell’ambito dello Strumento e la Commissione trasmette tali informazioni all’Agenzia europea della guardia di frontiera e costiera.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Le attrezzature e i sistemi TIC di cui al primo comma sono ammissibili al sostegno finanziario a titolo del presente Strumento se è rispettato il requisito di cui alla lettera a) del primo comma.</p>"], [null, "<p class=\"norm\">Ai fini della lettera c) del primo comma, le attrezzature e i sistemi TIC restano disponibili e utilizzabili per attività di controllo alle frontiere efficaci e sicure. L’uso di attrezzature nei settori complementari di cui alla lettera c) del primo comma non supera il 30 % del periodo totale di utilizzo di tali attrezzature. I sistemi TIC sviluppati ai fini della lettera c) del primo comma forniscono dati e servizi ai sistemi di gestione delle frontiere a livello nazionale o dell’Unione. Nella relazione annuale in materia di performance gli Stati membri informano la Commissione di eventuali usi multipli di cui alla lettera c) del primo comma e del luogo di utilizzo delle attrezzature multifunzionali e dei sistemi TIC.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">15.  </span>\n<div class=\"norm inline-element\">Nel condurre azioni nell’ambito dello Strumento, gli Stati membri prestano particolare attenzione ai loro obblighi internazionali in materia di operazioni di ricerca e soccorso in mare. Le attrezzature e i sistemi TIC di cui al paragrafo 14, primo comma, lettere da a) a d), possono essere utilizzati per affrontare operazioni di ricerca e soccorso in situazioni che si presentino durante un’operazione di sorveglianza delle frontiere in mare.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">16.  </span>\n<div class=\"norm inline-element\">La formazione in materia di gestione delle frontiere realizzata con il sostegno dello Strumento si basa sui pertinenti standard comuni europei, armonizzati e di qualità, in materia di formazione e di istruzione per le guardie di frontiera e costiere, in particolare il programma comune di base di cui all’articolo 62, paragrafo 6, del regolamento (UE) 2019/1896.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">17.  </span>\n<div class=\"norm inline-element\">Nei loro programmi, gli Stati membri perseguono in particolare le azioni elencate nell’allegato IV. Per far fronte a circostanze impreviste o nuove e per garantire l’efficace esecuzione dei finanziamenti, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 31 per modificare l’elenco delle azioni ammissibili a tassi di cofinanziamento più elevati di cui all’allegato IV.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">18.  </span>\n<div class=\"norm inline-element\">La programmazione di cui all’articolo 22, paragrafo 5, del regolamento (UE) 2021/1060 è basata sulle tipologie di intervento indicate nella tabella 1 dell’allegato VI del presente regolamento e comprende una ripartizione indicativa delle risorse programmate per tipologia di intervento nell’ambito di ciascun obiettivo specifico indicato all’articolo 3, paragrafo 2, del presente regolamento.</div>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Revisione intermedia", "anchor": "art_14", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Nel 2024 la Commissione assegna ai programmi degli Stati membri interessati l’importo aggiuntivo di cui all’articolo 10, paragrafo 1, lettera b), conformemente ai criteri di cui all’allegato I, punto 1, lettera c), e punti da 2 a 10. Tale assegnazione è basata sui più recenti dati statistici disponibili per i criteri di cui al punto 1, lettera c), e ai punti da 2 a 10 dell’allegato I. Il finanziamento ha effetto a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2025.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora almeno il 10 % della dotazione iniziale di un programma di cui all’articolo 10, paragrafo 1, lettera a), del presente regolamento non sia stato oggetto di domande di pagamento intermedio presentate conformemente all’articolo 91 del regolamento (UE) 2021/1060, lo Stato membro interessato non è ammesso a ricevere la dotazione aggiuntiva per il rispettivo programma di cui all’articolo 10, paragrafo 1, lettera b), del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nell’assegnazione dei fondi provenienti dallo strumento tematico di cui all’articolo 8 del presente regolamento a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2025, la Commissione tiene conto dei progressi compiuti dagli Stati membri nel raggiungimento dei target intermedi del quadro di riferimento dell’efficacia dell’attuazione di cui all’articolo 16 del regolamento (UE) 2021/1060 e delle lacune individuate nell’attuazione.</div>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Azioni specifiche", "anchor": "art_15", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può ricevere finanziamenti per azioni specifiche in aggiunta alla sua dotazione a norma dell’articolo 10, paragrafo 1, purché tali finanziamenti siano successivamente destinati come tali nel suo programma e siano usati per contribuire alla realizzazione degli obiettivi dello Strumento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I finanziamenti per le azioni specifiche non possono essere usati per altre azioni del programma degli Stati membri, tranne in casi debitamente giustificati e previa approvazione della Commissione mediante modifica del programma degli Stati membri.</div>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Sostegno operativo", "anchor": "art_16", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può utilizzare fino al 33 % dell’importo stanziato per il suo programma nell’ambito dello Strumento per finanziare il sostegno operativo alle autorità pubbliche responsabili dello svolgimento dei compiti e della fornitura dei servizi che costituiscono un servizio pubblico per l’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Quando utilizzano il sostegno operativo, gli Stati membri si conformano al pertinente acquis dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri illustrano, nel programma e nelle relazioni annuale in materia di performance di cui all’articolo 29, in che modo l’uso del sostegno operativo contribuirà al conseguimento degli obiettivi dello Strumento. Prima dell’approvazione del programma degli Stati membri, e previa consultazione dell’Agenzia europea della guardia di frontiera e costiera e, se del caso, di eu-LISA nell’ambito di competenza di tali agenzie a norma dell’articolo 13, paragrafo 4, la Commissione valuta la situazione di partenza negli Stati membri che hanno espresso l’intenzione di usare il sostegno operativo, tenendo conto delle informazioni fornite da tali Stati membri e, se del caso, delle informazioni disponibili in esito alle valutazioni Schengen e alle valutazioni delle vulnerabilità, comprese le raccomandazioni a seguito di valutazioni Schengen e di valutazioni della vulnerabilità.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Fermo restando l’articolo 5, paragrafo 4, lettera c), il sostegno operativo riguarda le spese coperte dalle spese stabilite nell’allegato VII.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Per far fronte a circostanze impreviste o nuove o per garantire l’efficace esecuzione dei finanziamenti, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 31 per modificare l’allegato VII in relazione alle spese ammissibili al sostegno operativo.</div>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Sostegno operativo per il regime di transito speciale", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Lo Strumento prevede un sostegno per coprire i diritti non riscossi per i visti di transito e i costi supplementari sostenuti per l’attuazione del regime di transito agevolato in conformità dei regolamenti (CE) n. 693/2003 e (CE) n. 694/2003 del Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le risorse assegnate alla Lituania per il regime di transito speciale a norma dell’articolo 7, paragrafo 3, lettera a), sono rese disponibili come sostegno operativo supplementare per la Lituania, anche per investimenti in infrastrutture, in conformità delle spese ammissibili al sostegno operativo nell’ambito del suo programma di cui all’allegato VII.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 16, paragrafo 1, la Lituania può utilizzare gli importi ad essa assegnati conformemente all’articolo 7, paragrafo 3, lettera a), per finanziare il sostegno operativo in aggiunta all’importo di cui all’articolo 16, paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione e la Lituania riesaminano l’applicazione del presente articolo qualora subentrino cambiamenti tali da incidere sull’esistenza o sul funzionamento del regime di transito speciale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In seguito a una richiesta motivata da parte della Lituania, le risorse assegnate per il regime di transito speciale di cui all’articolo 7, paragrafo 3, lettera a), sono riesaminate e, se necessario, adeguate prima dell’adozione dell’ultimo programma di lavoro per lo strumento tematico di cui all’articolo 8, nei limiti delle risorse di bilancio di cui all’articolo 7, paragrafo 3, lettera b), attraverso lo strumento tematico di cui all’articolo 8.</div>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Verifiche di gestione e audit dei progetti realizzati da organizzazioni internazionali", "anchor": "art_18", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente articolo si applica alle organizzazioni internazionali o loro agenzie di cui all’articolo 62, paragrafo 1, primo comma, lettera c), punto ii), del regolamento finanziario i cui sistemi, norme e procedure sono stati valutati positivamente dalla Commissione a norma dell’articolo 154, paragrafi 4 e 7, di detto regolamento ai fini dell’esecuzione indiretta di sovvenzioni finanziate a titolo del bilancio dell’Unione («organizzazioni internazionali»).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatti salvi l’articolo 83, primo comma, lettera a) del regolamento (UE) 2021/1060 e l’articolo 129 del regolamento finanziario, se l’organizzazione internazionale è un beneficiario ai sensi dell’articolo 2, punto 9), del regolamento (UE) 2021/1060, l’autorità di gestione non è tenuta ad effettuare le verifiche di gestione di cui all’articolo 74, paragrafo 1, primo comma, lettera a), del regolamento (UE) 2021/1060, a condizione che l’organizzazione internazionale trasmetta all’autorità di gestione i documenti di cui all’articolo 155, paragrafo 1, primo comma, lettere a), b) e c), del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 155, paragrafo 1, primo comma, lettera c), del regolamento finanziario, la dichiarazione di gestione che l’organizzazione internazionale deve presentare conferma che il progetto rispetta il diritto applicabile e le condizioni per il suo sostegno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Inoltre, se i costi devono essere rimborsati a norma dell’articolo 53, paragrafo 1, lettera a), del regolamento (UE) 2021/1060, la dichiarazione di gestione che l’organizzazione internazionale deve presentare conferma che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le fatture e la prova del loro pagamento da parte del beneficiario sono state verificate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le registrazioni contabili o i codici contabili tenuti dal beneficiario per le operazioni collegate alle spese dichiarate all’autorità di gestione sono stati verificati.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se i costi devono essere rimborsati a norma dell’articolo 53, paragrafo 1, lettera b), c) o d), del regolamento (UE) 2021/1060, la dichiarazione di gestione presentata dall’organizzazione internazionale deve presentare conferma che sono state rispettate le condizioni per il rimborso delle spese.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">I documenti di cui all’articolo 155, paragrafo 1, primo comma, lettere a) e c), del regolamento finanziario sono forniti all’autorità di gestione unitamente a ciascuna domanda di pagamento presentata dal beneficiario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Ogni anno, entro il 15 ottobre, il beneficiario presenta i conti all’autorità di gestione. I conti sono corredati del parere di un organismo di audit indipendente, elaborato conformemente a principi di audit riconosciuti a livello internazionale. Detto parere accerta se i sistemi di controllo istituiti funzionano correttamente e sono efficaci in termini di costi e se le operazioni sottostanti sono legittime e regolari. Il parere riferisce altresì se l’esercizio di audit mette in dubbio le asserzioni contenute nelle dichiarazioni di gestione presentate dall’organizzazione internazionale, comprese le informazioni sui sospetti di frode. Il parere fornisce la garanzia che le spese incluse nelle domande di pagamento presentate dall’organizzazione internazionale all’autorità di gestione sono legali e regolari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Fatte salve le possibilità esistenti di effettuare ulteriori audit di cui all’articolo 127 del regolamento finanziario, l’autorità di gestione redige la dichiarazione di gestione di cui all’articolo 74, paragrafo 1, primo comma, lettera f), del regolamento (UE) 2021/1060. L’autorità di gestione vi procede sulla base dei documenti forniti dall’organizzazione internazionale a norma dei paragrafi da 2 a 5 e del paragrafo 7 del presente articolo, anziché basarsi sulle verifiche di gestione di cui all’articolo 74, paragrafo 1, di tale regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Il documento che specifica le condizioni per il sostegno di cui all’articolo 73, paragrafo 3, del regolamento (UE) 2021/1060 comprende i requisiti di cui al presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il paragrafo 2 non si applica e, di conseguenza, l’autorità di gestione è tenuta ad effettuare delle verifiche di gestione se:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tale autorità di gestione individua un rischio specifico di irregolarità o un’indicazione di frode in relazione a un progetto avviato o attuato dall’organizzazione internazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’organizzazione internazionale non presenta a tale autorità di gestione i documenti di cui ai paragrafi da 2 a 5 e al paragrafo 7; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i documenti di cui ai paragrafi da 2 a 5 e al paragrafo 7 presentati dall’organizzazione internazionale sono incompleti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">Se un progetto in cui un’organizzazione internazionale è un beneficiario ai sensi dell’articolo 2, punto 9), del regolamento (UE) 2021/1060 fa parte di un campione di cui all’articolo 79 dello stesso, l’autorità di audit può svolgere il proprio lavoro sulla base di un sottocampione di operazioni relative a tale progetto. Se nel sottocampione sono riscontrati errori, l’autorità di audit, se del caso, può chiedere al revisore dell’organizzazione internazionale di valutare l’intera portata e l’importo totale degli errori in tale progetto.</div>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Ambito di applicazione", "anchor": "art_19", "frags": [[null, "<p class=\"norm\">La Commissione dà attuazione al sostegno di cui alla presente sezione direttamente, in conformità dell’articolo 62, paragrafo 1, primo comma, lettera a), del regolamento finanziario, o indirettamente, in conformità della lettera c) del medesimo comma.</p>"]]}, "20": {"label": "Articolo 20", "heading": "Soggetti ammissibili", "anchor": "art_20", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sono ammissibili al finanziamento dell’Unione i seguenti soggetti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i soggetti giuridici stabiliti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in uno Stato membro o un paese o territorio d’oltremare a esso connesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in un paese terzo elencato nel programma di lavoro, alle condizioni specificate al paragrafo 3;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i soggetti giuridici costituiti a norma del diritto dell’Unione o le organizzazioni internazionali pertinenti ai fini dello Strumento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Non sono ammissibili al finanziamento dell’Unione le persone fisiche.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I soggetti di cui al paragrafo 1, lettera a), punto ii), partecipano nell’ambito di un consorzio costituito da almeno due soggetti indipendenti, di cui almeno uno è stabilito in uno Stato membro.</div>\n</div>"], [null, "<p class=\"norm\">I soggetti che partecipano nell’ambito di un consorzio di cui al primo comma del presente paragrafo garantiscono che le azioni a cui partecipano rispettino i principi sanciti dalla Carta e contribuiscano al conseguimento degli obiettivi dello Strumento.</p>"]]}, "21": {"label": "Articolo 21", "heading": "Azioni dell’Unione", "anchor": "art_21", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Su iniziativa della Commissione, lo Strumento può essere utilizzato per finanziare azioni dell’Unione relative agli obiettivi dello Strumento conformemente all’allegato III.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le azioni dell’Unione possono concedere finanziamenti in tutte le forme previste dal regolamento finanziario, segnatamente sovvenzioni, premi e appalti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le sovvenzioni attuate in regime di gestione diretta sono concesse e gestite conformemente al titolo VIII del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I membri del comitato di valutazione che valuta le proposte, di cui all’articolo 150 del regolamento finanziario, possono essere esperti esterni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I contributi a un meccanismo di mutua assicurazione possono coprire il rischio associato al recupero dei fondi dovuti dai destinatari e sono considerati una garanzia sufficiente a titolo del regolamento finanziario. Si applica l’articolo 37, paragrafo 7, del regolamento (UE) 2021/695 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">3</span>\n).</div>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Assistenza tecnica su iniziativa della Commissione", "anchor": "art_22", "frags": [[null, "<p class=\"norm\">In conformità dell’articolo 35 del regolamento (UE) 2021/1060, lo Strumento può sostenere misure di assistenza tecnica attuate su iniziativa o per conto della Commissione a un tasso di finanziamento del 100 %.</p>"]]}, "23": {"label": "Articolo 23", "heading": "Audit", "anchor": "art_23", "frags": [[null, "<p class=\"norm\">Gli audit sull’uso del contributo dell’Unione effettuati da persone o soggetti anche diversi da quelli autorizzati dalle istituzioni, degli organi o dagli organismi dell’Unione costituiscono la base della garanzia globale di affidabilità a norma dell’articolo 127 del regolamento finanziario.</p>"]]}, "24": {"label": "Articolo 24", "heading": "Informazione, comunicazione e pubblicità", "anchor": "art_24", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I destinatari dei finanziamenti dell’Unione rendono nota l’origine degli stessi e ne garantiscono la visibilità, in particolare quando promuovono le azioni e i relativi risultati, fornendo informazioni mirate coerenti, efficaci e proporzionate a destinatari diversi, compresi i media e il pubblico. È garantita la visibilità dei finanziamenti dell’Unione e sono fornite informazioni, eccetto in casi debitamente giustificati in cui non sia possibile o appropriata esporre pubblicamente tali informazioni o la divulgazione di tali informazioni sia soggetta a restrizioni per legge, in particolare per ragioni di sicurezza, ordine pubblico, indagini penali o protezione dei dati personali. Al fine di garantire la visibilità dei finanziamenti dell’Unione, i destinatari di tali finanziamenti fanno riferimento all’origine di tali finanziamenti quando comunicano pubblicamente in merito alle azioni in questione ed espongono l’emblema dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Al fine di raggiungere il più ampio pubblico possibile, la Commissione realizza azioni di informazione e comunicazione sullo Strumento, sulle azioni svolte a titolo dello Strumento e sui risultati ottenuti.</div>\n</div>"], [null, "<p class=\"norm\">Le risorse finanziarie destinate allo Strumento contribuiscono anche alla comunicazione istituzionale delle priorità politiche dell’Unione nella misura in cui tali priorità si riferiscono agli obiettivi dello Strumento.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione pubblica i programmi di lavoro dello strumento tematico di cui all’articolo 8. Per il sostegno fornito in regime di gestione diretta o indiretta, la Commissione pubblica le informazioni di cui all’articolo 38, paragrafo 2, del regolamento finanziario su un sito web accessibile al pubblico e aggiorna regolarmente tali informazioni. Tali informazioni sono pubblicate in un formato aperto e leggibile meccanicamente che consente di selezionare, ricercare, estrarre e comparare i dati.</div>\n</div>"]]}, "25": {"label": "Articolo 25", "heading": "Assistenza emergenziale", "anchor": "art_25", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il Fondo fornisce assistenza finanziaria per far fronte a necessità urgenti e specifiche in caso di situazioni di emergenza debitamente giustificate.</div>\n</div>"], [null, "<p class=\"norm\">In risposta a tali situazioni di emergenza debitamente giustificate, la Commissione può fornire assistenza emergenziale entro i limiti delle risorse disponibili.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’assistenza emergenziale può consistere in sovvenzioni accordate direttamente alle agenzie decentrate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’assistenza emergenziale può essere assegnata ai programmi degli Stati membri in aggiunta alla dotazione di cui all’articolo 10, paragrafo 1, purché sia successivamente stanziata come tale nei programmi degli Stati membri. Tali finanziamenti non possono essere usati per altre azioni del programma degli Stati membri, tranne in casi debitamente giustificati e previa approvazione della Commissione mediante modifica del programma degli Stati membri. Il prefinanziamento per l’assistenza emergenziale può ammontare al 95 % del contributo dell’Unione, subordinatamente alla disponibilità di finanziamenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le sovvenzioni attuate in regime di gestione diretta sono concesse e gestite conformemente al titolo VIII del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Laddove necessario per realizzare un’azione, l’assistenza emergenziale può coprire le spese sostenute prima della data di presentazione della domanda di sovvenzione o della domanda di assistenza per l’azione stessa, purché tali spese non siano state sostenute anteriormente al 1<span class=\"superscript\">o</span> gennaio 2021.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’assistenza emergenziale è fornita nel rigoroso rispetto sia del pertinente acquis dell’Unione sia degli obblighi internazionali dell’Unione e degli Stati membri derivanti dagli strumenti internazionali di cui sono parti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Per imperativi motivi di urgenza debitamente giustificati e per garantire la tempestiva disponibilità di risorse per l’assistenza emergenziale, la Commissione può adottare separatamente una decisione di finanziamento, di cui all’articolo 110 del regolamento finanziario, per l’assistenza emergenziale mediante un atto di esecuzione immediatamente applicabile secondo la procedura di cui all’articolo 32, paragrafo 4. Tale atto rimane in vigore per un periodo non superiore a 18 mesi.</div>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Finanziamento cumulativo e alternativo", "anchor": "art_26", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Un’azione che abbia beneficiato di un contributo nell’ambito dello Strumento può essere finanziata anche da un altro programma dell’Unione, compresi i fondi in regime di gestione concorrente, purché tali contributi non riguardino gli stessi costi. Al contributo fornito all’azione da un programma dell’Unione si applicano le norme che disciplinano tale programma. Il finanziamento cumulativo non supera i costi totali ammissibili dell’azione e il sostegno proveniente dai diversi programmi dell’Unione può essere calcolato proporzionalmente in conformità dei documenti che specificano le condizioni per il sostegno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In conformità dell’articolo 73, paragrafo 4, del regolamento (UE) 2021/1060, il Fondo europeo di sviluppo regionale o il Fondo sociale europeo Plus possono sostenere le azioni che hanno ricevuto un marchio di eccellenza quale definito all’articolo 2, punto 45), di tale regolamento. Al fine di ricevere un marchio di eccellenza, le azioni devono essere conformi alle seguenti condizioni cumulative:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono state valutate nel quadro di un invito a presentare proposte nell’ambito dello Strumento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono conformi ai requisiti minimi di qualità indicati nell’invito a presentare proposte; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non possono essere finanziate nel quadro dell’invito a presentare proposte a causa di vincoli di bilancio.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Sorveglianza e rendicontazione", "anchor": "art_27", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Conformemente agli obblighi di rendicontazione a norma dell’articolo 41, paragrafo 3, primo comma, lettera h), punto iii), del regolamento finanziario, la Commissione trasmette al Parlamento europeo e al Consiglio informazioni sugli indicatori chiave di performance elencati nell’allegato V del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 31 per modificare l’allegato V allo scopo di apportare le modifiche necessarie agli indicatori chiave di performance elencati in tale allegato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli indicatori da utilizzare per rendere conto dei progressi dello Strumento nel conseguire gli obiettivi specifici indicati all’articolo 3, paragrafo 2, figurano nell’allegato VIII. Per gli indicatori di output, i valori base sono fissati a zero. I target intermedi fissati per il 2024 e i target finali fissati per il 2029 sono cumulativi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione riferisce anche in merito all’uso dello strumento tematico di cui all’articolo 8 destinata a sostenere azioni nei paesi terzi o in relazione a tali paesi e alla quota di strumento tematico utilizzata per sostenere tali azioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il sistema di rendicontazione in materia di performance garantisce una raccolta efficiente, efficace e tempestiva dei dati per la sorveglianza dell’attuazione e dei risultati del programma. A tal fine sono imposti obblighi di rendicontazione proporzionati ai destinatari dei finanziamenti dell’Unione e, se del caso, agli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Al fine di garantire una valutazione efficace dei progressi dello Strumento nel conseguire i suoi obiettivi, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 31 per modificare l’allegato VIII allo scopo di rivedere o completare gli indicatori, ove considerato necessario, e per integrare il presente regolamento con disposizioni sull’istituzione di un quadro di sorveglianza e di valutazione, anche in relazione alle informazioni che gli Stati membri devono fornire. Un’eventuale modifica dell’allegato VIII si applica soltanto ai progetti selezionati dopo l’entrata in vigore della modifica stessa.</div>\n</div>"]]}, "28": {"label": "Articolo 28", "heading": "Valutazione", "anchor": "art_28", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Entro il 31 dicembre 2024 la Commissione effettua una valutazione intermedia del presente regolamento. Oltre a quanto previsto dall’articolo 45, paragrafo 1, del regolamento (UE) 2021/1060, la valutazione intermedia esamina quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’efficacia dello Strumento, compresi i progressi compiuti nel conseguimento dei suoi obiettivi, tenendo conto di tutte le informazioni pertinenti disponibili, in particolare delle relazioni annuali in materia di performance di cui all’articolo 29 e degli indicatori di output e di risultato di cui all’allegato VIII;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’efficienza nell’uso delle risorse assegnate allo Strumento e l’efficienza delle misure di gestione e di controllo messe in atto per la sua attuazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il sussistere della pertinenza e dell’adeguatezza delle misure di attuazione elencate all’allegato II;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il coordinamento, la coerenza e la complementarità tra le azioni sostenute nell’ambito dello Strumento e il sostegno fornito da altri fondi dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il valore aggiunto dell’Unione delle azioni attuate nell’ambito dello Strumento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Tale valutazione intermedia tiene conto dei risultati della valutazione retrospettiva degli effetti dello strumento di sostegno finanziario per le frontiere esterne e i visti, quale parte del Fondo Sicurezza interna, per il periodo 2014-2020.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Oltre a quanto previsto dall’articolo 45, paragrafo 2, del regolamento (UE) 2021/1060, la valutazione retrospettiva comprende gli elementi elencati al paragrafo 1 del presente articolo. Va inoltre valutato l’impatto dello Strumento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La valutazione intermedia e la valutazione retrospettiva sono effettuate con tempestività per contribuire al processo decisionale, compresa, se del caso, la revisione del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione garantisce che le informazioni contenute nelle valutazioni intermedia e retrospettiva siano rese accessibili al pubblico, tranne in casi debitamente giustificati in cui la divulgazione delle informazioni sia soggetta a restrizioni per legge, in particolare per ragioni di funzionamento o di sicurezza delle frontiere esterne nell’ambito della gestione europea integrata delle frontiere, sicurezza, ordine pubblico, indagini penali o protezione dei dati personali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Nella valutazione intermedia e nella valutazione retrospettiva la Commissione presta particolare attenzione alla valutazione delle azioni realizzate con paesi terzi, in tali paesi o in relazione a essi, conformemente all’articolo 5 e all’articolo 13, paragrafi 12 e 13.</div>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Relazioni annuali in materia di performance", "anchor": "art_29", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Entro il 15 febbraio 2023 ed entro il 15 febbraio di ogni anno successivo fino al 2031 compreso, gli Stati membri trasmettono alla Commissione una relazione annuale in materia di performance di cui all’articolo 41, paragrafo 7, del regolamento (UE) 2021/1060.</div>\n</div>"], [null, "<p class=\"norm\">Il periodo di riferimento copre l’ultimo periodo contabile, come definito all’articolo 2, punto 29), del regolamento (UE) 2021/1060, precedente l’anno di trasmissione della relazione. La relazione presentata entro il 15 febbraio 2023 copre il periodo che decorre dal 1<span class=\"superscript\">o</span> gennaio 2021.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le relazioni annuali in materia di performance contengono in particolare informazioni riguardanti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i progressi compiuti nell’attuazione del programma dello Stato membro e nel conseguimento dei target intermedi e target finali ivi fissati, tenuto conto dei dati più recenti secondo quanto disposto all’articolo 42 del regolamento (UE) 2021/1060;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a bis) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attuazione delle azioni di solidarietà, comprese una ripartizione dei contributi finanziari per azioni e una descrizione dei principali risultati conseguiti grazie ai finanziamenti;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tutte le questioni che incidono sulla performance del programma dello Stato membro e le misure adottate per farvi fronte, ivi comprese informazioni su pareri motivati emessi dalla Commissione in relazione a procedure d’infrazione a norma dell’articolo 258 TFUE connesse all’attuazione dello Strumento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la complementarità tra le azioni sostenute nell’ambito dello Strumento e il sostegno fornito da altri fondi dell’Unione, in particolare le azioni intraprese nei paesi terzi o in relazione a tali paesi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il contributo del programma dello Stato membro all’attuazione dell’acquis e dei piani d’azione dell’Unione pertinenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attuazione di azioni di comunicazione e di visibilità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il soddisfacimento delle condizioni abilitanti applicabili e la loro applicazione durante l’intero periodo di programmazione, in particolare il rispetto dei diritti fondamentali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il livello delle spese in conformità dell’articolo 85, paragrafi 2 e 3, del regolamento (UE) 2018/1240, anche nei conti a norma dell’articolo 98 del regolamento (UE) 2021/1060.</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attuazione di progetti in un paese terzo o in relazione a un paese terzo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Le relazioni annuali in materia di performance comprendono una sintesi relativa a tutti i punti di cui al primo comma del presente paragrafo. La Commissione provvede affinché le sintesi fornite dagli Stati membri siano tradotte in tutte le lingue ufficiali dell’Unione e rese pubbliche.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione ha la facoltà di formulare osservazioni sulle relazioni annuali in materia di performance entro due mesi dalla data di ricezione. Qualora la Commissione non formuli osservazioni entro tale termine, la relazione s’intende accettata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Sul proprio sito web, la Commissione fornisce il collegamento ai siti web di cui all’articolo 49, paragrafo 1, del regolamento (UE) 2021/1060.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Al fine di garantire condizioni uniformi di esecuzione del presente articolo, la Commissione adotta un atto di esecuzione che stabilisce il modello della relazione annuale in materia di performance. Tale atto di esecuzione è adottato secondo la procedura consultiva di cui all’articolo 32, paragrafo 2.</div>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Sorveglianza e rendicontazione in regime di gestione concorrente", "anchor": "art_30", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per la sorveglianza e la rendicontazione di cui al titolo IV del regolamento (UE) 2021/1060 sono utilizzati, ove opportuno, i codici per le tipologie di intervento indicate all’allegato VI del presente regolamento. Per far fronte a circostanze impreviste o nuove e per garantire l’efficace esecuzione dei finanziamenti, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 31 per modificare l’allegato VI.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli indicatori di cui all’allegato VIII del presente regolamento sono usati conformemente all’articolo 16, paragrafo 1, e agli articoli 22 e 42 del regolamento (UE) 2021/1060.</div>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Esercizio della delega", "anchor": "art_31", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui all’articolo 5, paragrafo 1, secondo comma, articolo 13, paragrafo 17, articolo 16, paragrafo 5, all’articolo 27, paragrafi 2 e 6, e all’articolo 30, paragrafo 1, è conferito alla Commissione fino al 31 dicembre 2027.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La delega di potere di cui all’articolo 5, paragrafo 1, secondo comma, articolo 13, paragrafo 17, articolo 16, paragrafo 5, all’articolo 27, paragrafi 2 e 6, e all’articolo 30, paragrafo 1, può essere revocata in qualsiasi momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega di potere ivi specificata. Gli effetti della decisione decorrono dal giorno successivo alla pubblicazione della decisione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span> o da una data successiva ivi specificata. Essa non pregiudica la validità degli atti delegati già in vigore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Prima dell’adozione dell’atto delegato la Commissione consulta gli esperti designati da ciascuno Stato membro nel rispetto dei principi stabiliti nell’accordo interistituzionale «Legiferare meglio» del 13 aprile 2016.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’atto delegato adottato ai sensi dell’articolo 5, paragrafo 1, secondo comma, dell’articolo 13, paragrafo 17, dell’articolo 16, paragrafo 5, dell’articolo 27, paragrafi 2 e 6, e dell’articolo 30, paragrafo 1, entra in vigore solo se né il Parlamento europeo né il Consiglio hanno sollevato obiezioni entro il termine di due mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno informato la Commissione che non intendono sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</div>\n</div>"]]}, "32": {"label": "Articolo 32", "heading": "Procedura di comitato", "anchor": "art_32", "frags": [[null, "<p class=\"modref\">\n▼C1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione è assistita da un comitato («comitato per i fondi per gli affari interni»). Esso è un comitato ai sensi del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l’articolo 4 del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l’articolo 5 del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<p class=\"norm\">Qualora il comitato non esprima alcun parere, la Commissione non adotta il progetto di atto di esecuzione e si applica l’articolo 5, paragrafo 4, terzo comma, del regolamento (UE) n. 182/2011.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l’articolo 8 del regolamento (UE) n. 182/2011 in combinato disposto con il suo articolo 5.</div>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Disposizioni transitorie", "anchor": "art_33", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente regolamento non pregiudica il proseguimento o la modifica di azioni avviate interessate ai sensi del regolamento (UE) n. 515/2014, che continua pertanto ad applicarsi a tali azioni fino alla loro chiusura.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La dotazione finanziaria dello Strumento può anche coprire le spese di assistenza tecnica e amministrativa necessarie per assicurare la transizione tra lo Strumento e le misure adottate ai sensi del regolamento (UE) n. 515/2014.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">A norma dell’articolo 193, paragrafo 2, secondo comma, lettera a), del regolamento finanziario, tenuto conto del ritardo nell’entrata in vigore del presente regolamento e al fine di garantire la continuità, per un periodo limitato i costi sostenuti in relazione ad azioni già avviate che beneficiano di sostegno a norma del presente regolamento in regime di gestione diretta possono essere considerati ammissibili al finanziamento a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2021, anche se tali costi sono stati sostenuti prima della presentazione della domanda di sovvenzione o della domanda di assistenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri possono continuare dopo il 1<span class=\"superscript\">o</span> gennaio 2021 a sostenere un progetto selezionato e avviato a norma del regolamento (UE) n. 515/2014, conformemente al regolamento (UE) n. 514/2014, purché siano soddisfatte tutte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il progetto presenta due fasi distinguibili sotto l’aspetto finanziario e piste di controllo distinte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il costo totale del progetto è superiore a 2 500 000  EUR;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i pagamenti versati ai beneficiari dall’autorità responsabile per la prima fase del progetto sono inclusi nelle richieste di pagamento trasmesse alla Commissione a norma del regolamento (UE) n. 514/2014 e le spese per la seconda fase del progetto sono incluse nelle domande di pagamento a norma del regolamento (UE) 2021/1060;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la seconda fase del progetto ottempera al diritto applicabile ed è ammissibile al sostegno dello Strumento a norma del presente regolamento e del regolamento (UE) 2021/1060;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro si impegna a completare il progetto, a renderlo operativo e a riferirne nella relazione annuale in materia di performance presentata entro il 15 febbraio 2024.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Le disposizioni del presente regolamento e del regolamento (UE) 2021/1060 si applicano alla seconda fase di un progetto di cui al primo comma del presente paragrafo.</p>"], [null, "<p class=\"norm\">Il presente paragrafo si applica solo ai progetti selezionati in regime di gestione concorrente a norma del regolamento (UE) n. 514/2014.</p>"]]}, "34": {"label": "Articolo 34", "heading": "Entrata in vigore e applicazione", "anchor": "art_34", "frags": [[null, "<p class=\"norm\">Il presente regolamento entra in vigore il giorno della pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</p>"], [null, "<p class=\"norm\">Esso si applica a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2021.</p>"]]}}, "recitals": {}};